import kotlinx.coroutines.flow.*

suspend fun main() = runBlocking {
    // Test case 1: callbackFlow with timeout directly - should fail with exception
    val flow1 = callbackFlow<Int> {
        close(IllegalStateException("Test Exception"))
    }.timeout(5.seconds)
    try {
        flow1.collect()
    } catch (e: Exception) {
        println("Test 1 - exception got: $e")
    }

    // Test case 2: callbackFlow with catch then timeout - should work
    val flow2 = callbackFlow<Int> {
        close(IllegalStateException("Test Exception"))
    }.catch { throw it }.timeout(5.seconds)
    try {
        flow2.collect()
    } catch (e: Exception) {
        println("Test 2 - exception got: $e")
    }

    // Test case 3: callbackFlow with collect without timeout - should work
    val flow3 = callbackFlow<Int> {
        close(IllegalStateException("Test Exception"))
    }
    try {
        flow3.collect()
    } catch (e: Exception) {
        println("Test 3 - exception got: $e")
    }
}"}

