{"file_path":"/project/CallbackFlowTimeoutFixTest.kt","content":"import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlin.test.*

class CallbackFlowTimeoutFixTest {

    @Test
    fun testCallbackFlowWithTimeoutShouldPropagateException() = runBlocking {
        // Test case 1: callbackFlow with timeout directly - should now throw the exception
        val flow1 = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        val exception1 = try {
            flow1.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(exception1)
        assertTrue(exception1 is IllegalStateException, "Expected IllegalStateException but got ${exception1?.javaClass?.simpleName}")
        assertEquals("Test Exception", exception1.message)
    }

    @Test
    fun testCallbackFlowWithCatchThenTimeoutShouldWork() = runBlocking {
        // Test case 2: callbackFlow with catch then timeout - should work as before
        val flow2 = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.catch { throw it }.timeout(5.seconds)

        val exception2 = try {
            flow2.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(exception2)
        assertTrue(exception2 is IllegalStateException, "Expected IllegalStateException but got ${exception2?.javaClass?.simpleName}")
        assertEquals("Test Exception", exception2.message)
    }

    @Test
    fun testCallbackFlowWithoutTimeoutShouldThrowException() = runBlocking {
        // Test case 3: callbackFlow without timeout - should work as before
        val flow3 = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }

        val exception3 = try {
            flow3.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(exception3)
        assertTrue(exception3 is IllegalStateException, "Expected IllegalStateException but got ${exception3?.javaClass?.simpleName}")
        assertEquals("Test Exception", exception3.message)
    }

    @Test
    fun testCallbackFlowWithTimeoutAndNormalCloseShouldCompleteNormally() = runBlocking {
        // Test case 4: callbackFlow with timeout and normal close - should complete normally
        val flow4 = callbackFlow<Int> {
            yield()
            close()  // Normal close without exception
        }.timeout(5.seconds)

        val exception4 = try {
            flow4.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNull(exception4, "Expected no exception but got ${exception4?.javaClass?.simpleName}: ${exception4?.message}")
    }

    @Test
    fun testCallbackFlowWithEmissionAndTimeout() = runBlocking {
        // Test case 5: callbackFlow with emissions and then timeout exception
        val flow5 = callbackFlow<Int> {
            send(1)
            send(2)
            close(IllegalStateException("Done"))
        }.timeout(5.seconds)

        val collectedValues = mutableListOf<Int>()
        val exception5 = try {
            flow5.collect { collectedValues.add(it) }
            null
        } catch (e: Exception) {
            e
        }

        assertEquals(listOf(1, 2), collectedValues)
        assertNotNull(exception5)
        assertTrue(exception5 is IllegalStateException, "Expected IllegalStateException but got ${exception5?.javaClass?.simpleName}")
        assertEquals("Done", exception5.message)
    }
}

// Main function to run the tests
fun main() = runTest {
    println("Running testCallbackFlowWithTimeoutShouldPropagateException...")
    testCallbackFlowWithTimeoutShouldPropagateException()
    println("PASSED")

    println("Running testCallbackFlowWithCatchThenTimeoutShouldWork...")
    testCallbackFlowWithCatchThenTimeoutShouldWork()
    println("PASSED")

    println("Running testCallbackFlowWithoutTimeoutShouldThrowException...")
    testCallbackFlowWithoutTimeoutShouldThrowException()
    println("PASSED")

    println("Running testCallbackFlowWithTimeoutAndNormalCloseShouldCompleteNormally...")
    testCallbackFlowWithTimeoutAndNormalCloseShouldCompleteNormally()
    println("PASSED")

    println("Running testCallbackFlowWithEmissionAndTimeout...")
    testCallbackFlowWithEmissionAndTimeout()
    println("PASSED")

    println("\nAll tests passed!")
}"}

